import java.util.Scanner;
import java.util.Arrays;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String userInput = scanner.nextLine();

        // Use a dynamically sized byte array to store user input
        byte[] buffer = new byte[userInput.length() > 10 ? 10 : userInput.length()];

        // Copy user input into the buffer with proper bounds checking
        System.arraycopy(userInput.getBytes(), 0, buffer, 0, Math.min(userInput.length(), buffer.length));

        System.out.println("Buffer contents: " + new String(buffer));
    }
}

